import { createClient } from '@supabase/supabase-js'
import { NextResponse } from 'next/server'
import { getCorsHeaders } from '@/lib/cors'
import { logger, getClientIp } from '@/lib/logger'
import { verifyExtensionToken } from '@/lib/verify-extension-token'

function getSupabaseAdmin() {
  return createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!
  )
}

export async function OPTIONS(request: Request) {
  const origin = request.headers.get('origin')
  return NextResponse.json(null, { headers: getCorsHeaders(origin) })
}

export async function GET(request: Request) {
  const origin = request.headers.get('origin')
  const corsHeaders = getCorsHeaders(origin)

  try {
    const supabase = getSupabaseAdmin()

    const ip = getClientIp(request)

    // Verify the extension token from Authorization header
    const tokenResult = await verifyExtensionToken(request)
    if (!tokenResult.valid) {
      logger.security('prompts.auth_failed', { ip, route: '/api/extension/prompts', reason: tokenResult.error })
      return NextResponse.json(
        { error: tokenResult.error || 'Unauthorized' },
        { status: 401, headers: corsHeaders }
      )
    }

    // Use the verified userId from the token, NOT from query params
    const userId = tokenResult.userId!

    // Get user's prompts
    const { data: prompts, error } = await supabase
      .from('prompts')
      .select('id, name, content, is_default, platform')
      .eq('user_id', userId)
      .order('is_default', { ascending: false })
      .order('created_at', { ascending: false })

    if (error) {
      logger.error('prompts.fetch_failed', { userId, dbError: error.message })
      return NextResponse.json(
        { error: 'Failed to fetch prompts' },
        { status: 500, headers: corsHeaders }
      )
    }

    // Get user profile for usage info
    const { data: profile, error: profileError } = await supabase
      .from('profiles')
      .select('id, plan, subscription_status, generations_count, generations_limit, daily_free_quota, monthly_quota, initial_quota, last_daily_reset, cancel_at_period_end, current_period_end')
      .eq('id', userId)
      .single()

    if (profileError) {
      console.error('[PROMPTS] Profile fetch error:', profileError.message)
    }

    // Lazy expiration: downgrade if cancelled subscription has expired
    if (
      profile &&
      profile.cancel_at_period_end &&
      profile.current_period_end &&
      new Date(profile.current_period_end) < new Date()
    ) {
      await supabase
        .from('profiles')
        .update({
          plan: 'free',
          subscription_status: 'expired',
          monthly_quota: 0,
          cancel_at_period_end: false,
        })
        .eq('id', userId)

      profile.plan = 'free'
      profile.monthly_quota = 0
    }

    // Daily quota reset check
    if (profile) {
      const now = new Date()
      const lastReset = profile.last_daily_reset ? new Date(profile.last_daily_reset) : new Date(0)
      if (now.toDateString() !== lastReset.toDateString()) {
        profile.daily_free_quota = 5
        profile.last_daily_reset = now.toISOString()
        await supabase
          .from('profiles')
          .update({ daily_free_quota: 5, last_daily_reset: now.toISOString() })
          .eq('id', userId)
      }
    }

    const dailyRemaining = profile?.daily_free_quota ?? 0
    const monthlyRemaining = profile?.monthly_quota ?? 0
    const initialRemaining = profile?.initial_quota ?? 0

    return NextResponse.json(
      {
        prompts: prompts || [],
        usage: profile
          ? {
            tier: profile.plan || 'free',
            daily_remaining: dailyRemaining,
            daily_limit: 5,
            monthly_remaining: monthlyRemaining,
            monthly_limit: profile.plan === 'ultra' ? 7000 : profile.plan === 'pro' ? 2000 : 0,
            initial_remaining: initialRemaining,
            total_remaining: dailyRemaining + monthlyRemaining + initialRemaining,
          }
          : null,
      },
      { headers: corsHeaders }
    )
  } catch (error) {
    logger.exception('prompts.error', error, { route: '/api/extension/prompts' })
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500, headers: corsHeaders }
    )
  }
}

export async function POST(request: Request) {
  const origin = request.headers.get('origin')
  const corsHeaders = getCorsHeaders(origin)

  try {
    const supabase = getSupabaseAdmin()
    const ip = getClientIp(request)

    const tokenResult = await verifyExtensionToken(request)
    if (!tokenResult.valid) {
      logger.security('prompts.create_auth_failed', { ip, route: '/api/extension/prompts', reason: tokenResult.error })
      return NextResponse.json(
        { error: tokenResult.error || 'Unauthorized' },
        { status: 401, headers: corsHeaders }
      )
    }

    const userId = tokenResult.userId!

    let body: unknown
    try {
      body = await request.json()
    } catch {
      return NextResponse.json({ error: 'Invalid JSON body' }, { status: 400, headers: corsHeaders })
    }

    const { name, content, platform = 'discord' } = body as Record<string, unknown>

    if (typeof name !== 'string' || !name.trim() || typeof content !== 'string' || !content.trim()) {
      return NextResponse.json({ error: 'Prompt name and content are required' }, { status: 400, headers: corsHeaders })
    }

    // Validate platform constraint
    const safePlatform = (platform === 'x' || platform === 'discord') ? platform : 'discord';

    const { data: newPrompt, error } = await supabase
      .from('prompts')
      .insert({
        user_id: userId,
        name: name.trim().slice(0, 100),
        content: content.trim().slice(0, 5000),
        is_default: false,
        platform: safePlatform
      })
      .select('id, name, is_default, platform')
      .single()

    if (error) {
      logger.error('prompts.create_failed', { userId, dbError: error.message })
      return NextResponse.json({ error: 'Failed to create prompt' }, { status: 500, headers: corsHeaders })
    }

    return NextResponse.json({ prompt: newPrompt }, { headers: corsHeaders })
  } catch (error) {
    logger.exception('prompts.post_error', error, { route: '/api/extension/prompts' })
    return NextResponse.json({ error: 'Internal server error' }, { status: 500, headers: corsHeaders })
  }
}

export async function PUT(request: Request) {
  const origin = request.headers.get('origin')
  const corsHeaders = getCorsHeaders(origin)

  try {
    const supabase = getSupabaseAdmin()
    const tokenResult = await verifyExtensionToken(request)
    if (!tokenResult.valid) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401, headers: corsHeaders })
    }

    const userId = tokenResult.userId!
    let body: unknown
    try { body = await request.json() } catch {
      return NextResponse.json({ error: 'Invalid JSON' }, { status: 400, headers: corsHeaders })
    }

    const { id, name, content } = body as Record<string, unknown>

    if (!id || typeof id !== 'string') {
      return NextResponse.json({ error: 'Missing prompt id' }, { status: 400, headers: corsHeaders })
    }
    if (typeof name !== 'string' || !name.trim()) {
      return NextResponse.json({ error: 'Prompt name is required' }, { status: 400, headers: corsHeaders })
    }

    const updateData: Record<string, string> = { name: name.trim().slice(0, 100) }
    if (typeof content === 'string') {
      updateData.content = content.trim().slice(0, 5000)
    }

    const { data: updated, error } = await supabase
      .from('prompts')
      .update(updateData)
      .eq('id', id)
      .eq('user_id', userId)
      .select('id, name, is_default, platform')
      .single()

    if (error) {
      logger.error('prompts.update_failed', { userId, dbError: error.message })
      return NextResponse.json({ error: 'Failed to update prompt' }, { status: 500, headers: corsHeaders })
    }

    return NextResponse.json({ prompt: updated }, { headers: corsHeaders })
  } catch (error) {
    logger.exception('prompts.put_error', error, { route: '/api/extension/prompts' })
    return NextResponse.json({ error: 'Internal server error' }, { status: 500, headers: corsHeaders })
  }
}

export async function DELETE(request: Request) {
  const origin = request.headers.get('origin')
  const corsHeaders = getCorsHeaders(origin)

  try {
    const supabase = getSupabaseAdmin()
    const tokenResult = await verifyExtensionToken(request)
    if (!tokenResult.valid) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401, headers: corsHeaders })
    }

    const userId = tokenResult.userId!
    const url = new URL(request.url)
    const promptId = url.searchParams.get('id')

    if (!promptId) {
      return NextResponse.json({ error: 'Missing prompt id' }, { status: 400, headers: corsHeaders })
    }

    const { error } = await supabase
      .from('prompts')
      .delete()
      .eq('id', promptId)
      .eq('user_id', userId)

    if (error) {
      logger.error('prompts.delete_failed', { userId, dbError: error.message })
      return NextResponse.json({ error: 'Failed to delete prompt' }, { status: 500, headers: corsHeaders })
    }

    return NextResponse.json({ success: true }, { headers: corsHeaders })
  } catch (error) {
    logger.exception('prompts.delete_error', error, { route: '/api/extension/prompts' })
    return NextResponse.json({ error: 'Internal server error' }, { status: 500, headers: corsHeaders })
  }
}
